import sys

def solve():
    input_data = sys.stdin.read().split()
    idx = 0
    N = int(input_data[idx]); idx += 1
    Q = int(input_data[idx]); idx += 1

    grid = []
    for i in range(N):
        row = list(input_data[idx])
        grid.append([int(c) for c in row])
        idx += 1

    for _ in range(Q):
        new_grid = [[0]*N for _ in range(N)]
        for i in range(N):
            for j in range(N):
                neighbors = 0
                for di in (-1, 0, 1):
                    for dj in (-1, 0, 1):
                        if di == 0 and dj == 0:
                            continue
                        ni, nj = i + di, j + dj
                        if 0 <= ni < N and 0 <= nj < N:
                            neighbors += grid[ni][nj]
                if grid[i][j] == 1:
                    if neighbors == 2 or neighbors == 3:
                        new_grid[i][j] = 1
                    else:
                        new_grid[i][j] = 0
                else:
                    if neighbors == 3:
                        new_grid[i][j] = 1
                    else:
                        new_grid[i][j] = 0
        grid = new_grid

    out = []
    for i in range(N):
        out.append(''.join(str(c) for c in grid[i]))
    print('\n'.join(out))

solve()

import sys
from functools import cmp_to_key

def upper_envelope(lines):
    lines.sort(key=lambda l: (l[0], l[1]))
    hull = []
    for a, b in lines:
        while len(hull) >= 2:
            a1, b1 = hull[-2]
            a2, b2 = hull[-1]
            if (b - b2) * (a1 - a2) >= (b2 - b1) * (a2 - a):<br>                hull.pop()
            else:
                break
        if hull and hull[-1][0] == a and hull[-1][1] <= b:
            hull.pop()
        hull.append((a, b))
    return hull

